import React from 'react';

interface OpenChamberLogoProps {
  className?: string;
  width?: number;
  height?: number;
  isAnimated?: boolean;
}

// Base64-encoded Spencer Fane logos for instant rendering (no network request)
const SF_ICON_B64 = 'data:image/png;base64,';
const SF_LOGO_B64 = 'data:image/webp;base64,';

export const OpenChamberLogo: React.FC<OpenChamberLogoProps> = ({
  className = '',
  width = 70,
  height = 70,
  isAnimated = false,
}) => {
  const src = width > 80 ? SF_LOGO_B64 : SF_ICON_B64;

  return (
    <div
      className={className}
      style={{
        width,
        height,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        animation: isAnimated ? 'sf-logo-pulse 3s ease-in-out infinite' : undefined,
      }}
    >
      <style>{`
        @keyframes sf-logo-pulse {
          0%, 100% { opacity: 0.85; }
          50% { opacity: 1; }
        }
      `}</style>
      <img
        src={src}
        alt="Spencer Fane"
        style={{
          maxWidth: '100%',
          maxHeight: '100%',
          objectFit: 'contain',
        }}
        draggable={false}
      />
    </div>
  );
};
